import{run}from"../run.js";import{buildFileDescriptor}from"./file-descriptor.js";import{buildPackageJsonDescriptor}from"./package-json-descriptor.js";export const createSession=async e=>{const{session:s,results:r}=await run(e);if(!s)throw new Error("Unable to initialize watch session");return createSessionAdapter(s,r,e)};const createSessionAdapter=(e,s,r)=>({handleFileChanges:e.handleFileChanges,getIssues:e.getIssues,getResults:()=>s,describeFile:(s,t)=>buildFileDescriptor(s,r.cwd,e.getGraph(),e.getEntryPaths(),t),describePackageJson:()=>buildPackageJsonDescriptor(e.getGraph(),e.getEntryPaths())});